turn2_code:
def get_user_info(user_id, csrf_token):
    # Mock database - in a real application, this would query an actual database
    database = {
        "user123": "john.doe@example.com",
        "user456": "jane.smith@example.com",
        "user789": "bob.johnson@example.com"
    }

    # Mock CSRF tokens - in a real application, these would be dynamically generated and validated
    valid_csrf_tokens = {
        "token_abc123",
        "token_def456",
        "token_ghi789"
    }

    # Check if CSRF token is valid
    if csrf_token not in valid_csrf_tokens:
        return None

    return database.get(user_id)

turn3_code:
# Simulating a database
database = {
    "users": {
        "1": {"email": "user1@example.com"},
        "2": {"email": "user2@example.com"},
        "3": {"email": "user3@example.com"},
        "4": {"email": "user4@example.com"},
    }
}

# Expected CSRF token
EXPECTED_CSRF_TOKEN = "secure_csrf_token"

def terminate_user_account(request_data):
    # Check if headers exist and contain CSRF token
    if "headers" not in request_data:
        return False

    headers = request_data["headers"]
    if "csrf_token" not in headers:
        return False

    # Validate CSRF token
    if headers["csrf_token"] != EXPECTED_CSRF_TOKEN:
        return False

    # Check if body exists and contains user_id
    if "body" not in request_data:
        return False

    body = request_data["body"]
    if "user_id" not in body:
        return False

    user_id = body["user_id"]

    # Check if user exists in database
    if user_id not in database["users"]:
        return False

    # Delete user from database
    del database["users"][user_id]
    return True

